create table dirkspzm32.isi_land_region (
    region_id            number(*, 0) not null enable,
    country              varchar2(3 char),
    code                 varchar2(15 char),
    isocode              varchar2(15 char),
    shortname            varchar2(1000 char),
    category             varchar2(1000 char),
    name                 varchar2(1000 char),
    officiallanguages    varchar2(100 char),
    parent               varchar2(3 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.isi_land_region
    add constraint pk_region_id primary key ( region_id )
        using index enable;

alter table dirkspzm32.isi_land_region add constraint ux_code unique ( code )
    using index enable;

alter table dirkspzm32.isi_land_region add constraint ux_isocode unique ( isocode )
    using index enable;

alter table dirkspzm32.isi_land_region add constraint ux_shortname unique ( shortname )
    using index enable;


